import React, { useState, useEffect } from 'react';
import { api } from '../services/api';
import { useCart } from '../context/CartContext';

const PanelCliente = () => {
    const [ofertas, setOfertas] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const { cart, addToCart, count, total, clearCart } = useCart();

    // 1. Cargar ofertas desde la nube
    useEffect(() => {
        const cargarDatos = async () => {
            try {
                setLoading(true);
                const data = await api.getTodasLasOfertas();
                setOfertas(data);
                setError(null);
            } catch (err) {
                console.error("Error al sincronizar:", err);
                setError("No se pudieron cargar las ofertas. Verifica la conexión.");
            } finally {
                setLoading(false);
            }
        };
        cargarDatos();
    }, []);

    // 2. Procesar la compra (Checkout)
    const handleCheckout = async () => {
        if (cart.length === 0) return alert("El carrito está vacío");

        const session = JSON.parse(localStorage.getItem('user-session'));
        if (!session || !session.userId) return alert("Debes iniciar sesión para comprar");

        try {
            const pedidoData = {
                clienteId: session.userId,
                puntoEntrega: {
                    direccion: "Retiro en sucursal" // Puedes cambiar esto por un input de dirección
                },
                // Mapeamos los items para que el backend reciba lo que espera
                items: cart.map(item => ({
                    producto: item.producto,      // minúscula según tu Schema
                    precio: item.precioNuevo,     // minúscula según tu Schema
                    cantidad: item.cantidad,
                    local: item.local._id || item.local // ID del local para agrupar pedidos
                }))
            };

            const res = await api.crearPedido(pedidoData);
            alert(`¡Compra exitosa! Se han generado ${res.cantidadPedidos} pedidos.`);
            clearCart();
        } catch (err) {
            alert("Error al procesar la compra: " + err.message);
        }
    };

    if (loading) return <div className="p-10 text-center">Cargando ofertas de la nube...</div>;

    return (
        <div className="max-w-6xl mx-auto p-4">
            <header className="flex justify-between items-center mb-8 bg-white p-4 rounded-lg shadow-sm">
                <h1 className="text-2xl font-bold text-blue-600">Tienda de Ofertas</h1>
                <div className="text-right">
                    <p className="font-semibold">Carrito: {count} productos</p>
                    <p className="text-green-600 font-bold">Total: ${total.toLocaleString()}</p>
                    {count > 0 && (
                        <button 
                            onClick={handleCheckout}
                            className="bg-green-500 text-white px-4 py-2 rounded mt-2 hover:bg-green-600 transition"
                        >
                            Finalizar Compra
                        </button>
                    )}
                </div>
            </header>

            {error && <div className="bg-red-100 text-red-700 p-4 rounded mb-4">{error}</div>}

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {ofertas.map((oferta) => (
                    <div key={oferta._id} className="border rounded-xl p-4 bg-white shadow-hover transition-shadow">
                        {/* Imagen del producto */}
                        <div className="h-48 bg-gray-100 rounded-lg mb-4 flex items-center justify-center overflow-hidden">
                            {oferta.url ? (
                                <img src={oferta.url} alt={oferta.producto} className="object-cover w-full h-full" />
                            ) : (
                                <span className="text-gray-400">Sin imagen</span>
                            )}
                        </div>

                        {/* Información sincronizada con minúsculas */}
                        <div className="flex justify-between items-start mb-2">
                            <h3 className="text-lg font-bold capitalize">{oferta.producto}</h3>
                            <span className="bg-blue-100 text-blue-800 text-xs px-2 py-1 rounded">
                                {oferta.categoria}
                            </span>
                        </div>

                        <p className="text-gray-500 text-sm mb-1">Local: {oferta.local?.nombre || 'General'}</p>
                        
                        <div className="flex items-center gap-3 mb-4">
                            <span className="text-2xl font-bold text-red-600">${oferta.precioNuevo}</span>
                            <span className="text-gray-400 line-through text-sm">${oferta.precioViejo}</span>
                        </div>

                        <div className="flex justify-between items-center">
                            <span className={`text-sm ${oferta.stock > 0 ? 'text-green-600' : 'text-red-600'}`}>
                                Stock: {oferta.stock} un.
                            </span>
                            <button 
                                onClick={() => addToCart(oferta)}
                                disabled={oferta.stock <= 0}
                                className={`px-4 py-2 rounded-lg font-medium transition ${
                                    oferta.stock > 0 
                                    ? 'bg-blue-600 text-white hover:bg-blue-700' 
                                    : 'bg-gray-300 text-gray-500 cursor-not-allowed'
                                }`}
                            >
                                {oferta.stock > 0 ? 'Agregar' : 'Agotado'}
                            </button>
                        </div>
                    </div>
                ))}
            </div>

            {ofertas.length === 0 && !loading && (
                <div className="text-center py-20 text-gray-500">
                    No hay ofertas publicadas en este momento.
                </div>
            )}
        </div>
    );
};

export default PanelCliente;
